def configure_kong_infrastructure(admin_url: str = "http://localhost:8001", 
                                 api_key: Optional[str] = None):
    client = KongAdminClient(admin_url, api_key)
    
    status = client.get_kong_status()
    logger.info(f"Kong Status: {status}")
    
    upstream = client.create_upstream(
        name="backend-upstream",
        algorithm="round-robin",
        healthchecks={
            "active": {
                "healthy": {
                    "interval": 5,
                    "successes": 2
                },
                "unhealthy": {
                    "interval": 5,
                    "tcp_failures": 2,
                    "http_failures": 3
                }
            },
            "passive": {
                "healthy": {
                    "successes": 2
                },
                "unhealthy": {
                    "tcp_failures": 2,
                    "http_failures": 3
                }
            }
        }
    )
    logger.info(f"Created upstream: {upstream['id']}")
    
    targets = [
        {"target": "backend1.example.com:8080", "weight": 100},
        {"target": "backend2.example.com:8080", "weight": 100},
        {"target": "backend3.example.com:8080", "weight": 50}
    ]
    
    for target_config in targets:
        target = client.create_target(
            upstream_id=upstream['name'],
            target=target_config['target'],
            weight=target_config['weight']
        )
        logger.info(f"Created target: {target['target']}")
    
    service = client.create_service(
        name="api-service",
        host="backend-upstream",
        port=80,
        protocol="http",
        path="/api",
        retries=5,
        connect_timeout=60000,
        write_timeout=60000,
        read_timeout=60000,
        tags=["production", "api"]
    )
    logger.info(f"Created service: {service['id']}")
    
    route = client.create_route(
        service_id=service['id'],
        name="api-route",
        protocols=["http", "https"],
        methods=["GET", "POST", "PUT", "DELETE"],
        paths=["/api"],
        strip_path=False,
        preserve_host=False,
        tags=["production"]
    )
    logger.info(f"Created route: {route['id']}")
    
    rate_limit = client.add_rate_limiting_plugin(
        service_id=service['id'],
        minute=100,
        hour=5000,
        policy="local",
        fault_tolerant=True,
        hide_client_headers=False
    )
    logger.info(f"Added rate limiting plugin: {rate_limit['id']}")
    
    size_limit = client.add_request_size_limiting_plugin(
        service_id=service['id'],
        allowed_payload_size=10
    )
    logger.info(f"Added request size limiting plugin: {size_limit['id']}")
    
    ip_restriction = client.add_ip_restriction_plugin(
        route_id=route['id'],
        deny=["0.0.0.0/0"]
    )
    logger.info(f"Added IP restriction plugin: {ip_restriction['id']}")
    
    logger.info("Kong configuration completed successfully")
    
    return {
        "upstream": upstream,
        "service": service,
        "route": route,
        "plugins": {
            "rate_limiting": rate_limit,
            "size_limiting": size_limit,
            "ip_restriction": ip_restriction
        }
    }


